"""
This module represents the game board and handles the placement and movement of pieces.
"""

class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces
        colors = ['R', 'B']  # Red and Black pieces
        for color in colors:
            if color == 'R':
                start_row = 0
            else:
                start_row = 5
            step = -1 if color == 'R' else 1
            for i in range(8):
                if (i + start_row) % 2 == 0:
                    self.board[start_row + i * step][i] = Piece(color, step)

    def print_board(self):
        for row in self.board:
            print(" ".join(piece.symbol if piece else '.' for piece in row))
```

#### `piece.py`
This module will represent a single checker piece.

```python
"""
This module represents a single checker piece.
"""

class Piece:
    def __init__(self, color, direction):
        self.color = color
        self.direction = direction
        self.is_king = False

    @property
    def symbol(self):
        if not self.is_king:
            return 'R' if self.color == 'red' else 'B'
        else:
            return 'RK' if self.color == 'red' else 'BK'

    def __str__(self):
        return self.symbol
```

